package main

import (
	"fmt"
	"math/rand"
	"time"
)

func GenerateSessionToken() string {
	rand.Seed(time.Now().UnixNano())
	letters := "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	token := make([]byte, 32)
	for i := range token {
		token[i] = letters[rand.Intn(len(letters))]
	}
	return fmt.Sprintf("%s", token)
}

